SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1000000000.0) AND (t.Risk_Rating <= 6) AND ((t.ID_LO_3Y-t.ID_HI_3Y)>265.0) AND (t.MA50/ NULLIF(t.MA200, 0)>0.92) AND (t.MA10/ NULLIF(t.MA200, 0)<1.24) AND (t.ROE5Y >0.05) AND (t.PE <20.0) AND (t.PE >4.0) AND (t.NP_P0 > 1.28*t.NP_P1) AND (t.NP_P1 > 0) AND (t.HI_3M_T1/ NULLIF(t.LO_3M_T1, 0)<2.0) AND (t.ROE_Min3Y >0.02) ORDER BY t.ticker, t.time